import { createTheme } from '@mui/material/styles';

const theme = createTheme({
  palette: {
    primary: {
      main: '#1a237e',
      contrastText: '#ffffff'
    },
    secondary: {
      main: '#64748b',
    },
    text: {
      primary: '#102a43',
      secondary: '#64748b'
    },
    background: {
      default: '#f7f9fc',
      paper: '#ffffff'
    }
  },
  typography: {
    fontFamily: ['Inter', 'Roboto', 'Helvetica', 'Arial', 'sans-serif'].join(','),
    h4: {
      fontWeight: 700
    },
    h5: {
      fontWeight: 700
    }
  },
  components: {
    MuiButton: {
      defaultProps: {
        disableElevation: true
      },
      styleOverrides: {
        root: {
          borderRadius: 4,
          backgroundColor: '#1a237e',
          color: '#ffffff',
          transition: 'background-color 0.1s linear',
          '&:hover': {
            backgroundColor: '#0d1b5e' // slightly darker
          }
        },
        outlined: {
          borderColor: '#1a237e',
          color: '#1a237e',
          '&:hover': {
            backgroundColor: '#1a237e',
            color: '#ffffff'
          }
        }
      }
    },
    MuiCard: {
      styleOverrides: {
        root: {
          borderRadius: 18
        }
      }
    }
  }
});

export default theme;
